# ================================================================
#  TraceWorks — SELF-CONTAINED ENGINE UPDATER
#  Run this ONE file. It contains the full engine embedded inside.
#  Right-click -> Run with PowerShell
# ================================================================

Clear-Host
Write-Host ""
Write-Host "  ╔══════════════════════════════════════════════╗" -ForegroundColor Yellow
Write-Host "  ║   TRACEWORKS — ENGINE UPDATER  v3.1         ║" -ForegroundColor Yellow
Write-Host "  ╚══════════════════════════════════════════════╝" -ForegroundColor Yellow
Write-Host ""

# ── DETECT PATHS ─────────────────────────────────────────────
$Desktop = [Environment]::GetFolderPath("Desktop")
$TW      = "$Desktop\TraceWorks"
$Engine  = "$TW\tw_engine.py"
$Backup  = "$TW\tw_engine.backup.py"
$Reports = "$TW\Reports"

Write-Host "  Desktop  : $Desktop" -ForegroundColor DarkGray
Write-Host "  Folder   : $TW" -ForegroundColor DarkGray
Write-Host ""

foreach ($dir in @($TW, $Reports)) {
    if (!(Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
}

# ── FIND PYTHON ───────────────────────────────────────────────
Write-Host "  Finding Python..." -ForegroundColor Cyan
$pythonCmd = $null
foreach ($cmd in @("python","python3","py")) {
    try { $v = & $cmd --version 2>&1; if ($v -match "Python 3") { $pythonCmd=$cmd; break } } catch {}
}
if (!$pythonCmd) {
    $storePaths = Get-ChildItem "$env:LOCALAPPDATA\Microsoft\WindowsApps" -Filter "python*.exe" -ErrorAction SilentlyContinue
    foreach ($p in $storePaths) {
        try { $v = & $p.FullName --version 2>&1; if ($v -match "Python 3") { $pythonCmd=$p.FullName; break } } catch {}
    }
}
if (!$pythonCmd) {
    $pkgPaths = Get-ChildItem "$env:LOCALAPPDATA\Packages" -Recurse -Filter "python.exe" -ErrorAction SilentlyContinue |
                Where-Object { $_.FullName -notlike "*Scripts*" } | Select-Object -First 3
    foreach ($p in $pkgPaths) {
        try { $v = & $p.FullName --version 2>&1; if ($v -match "Python 3") { $pythonCmd=$p.FullName; break } } catch {}
    }
}

if ($pythonCmd) {
    Write-Host "  ✓ Python: $( & $pythonCmd --version 2>&1 )" -ForegroundColor Green
} else {
    Write-Host "  ✗ Python not found. Install at: https://python.org/downloads" -ForegroundColor Red
    Write-Host "    Check 'Add to PATH' during install." -ForegroundColor Yellow
    Read-Host "  Press Enter to open download page"
    Start-Process "https://python.org/downloads"
    exit
}

# ── BACKUP EXISTING ENGINE ────────────────────────────────────
if (Test-Path $Engine) {
    Copy-Item $Engine $Backup -Force
    Write-Host "  ✓ Backed up old engine" -ForegroundColor DarkGray
}

# ── DECODE AND WRITE ENGINE ───────────────────────────────────
Write-Host ""
Write-Host "  [1/3] Extracting engine from installer..." -ForegroundColor Cyan

$b64 = ""

# Write b64 to temp file, decode from there (avoids quoting issues)
$b64File = "$env:TEMP\tw_b64_$([System.DateTime]::Now.Ticks).txt"
[System.IO.File]::WriteAllText($b64File, $b64, [System.Text.Encoding]::ASCII)

$decoded = & $pythonCmd -c "
import base64, gzip, sys
b64_path = sys.argv[1]
out_path  = sys.argv[2]
try:
    b64 = open(b64_path).read().strip()
    data = base64.b64decode(b64)
    original = gzip.decompress(data)
    with open(out_path, 'wb') as f:
        f.write(original)
    lines = original.decode('utf-8').count(chr(10))
    print('OK:' + str(lines))
except Exception as e:
    print('ERROR:' + str(e))
" "$b64File" "$Engine" 2>&1

Remove-Item $b64File -ErrorAction SilentlyContinue

if ($decoded -match "^OK:(\d+)") {
    $lines = $Matches[1]
    Write-Host "  ✓ Engine extracted — $lines lines" -ForegroundColor Green
} else {
    Write-Host "  ✗ Extraction failed: $decoded" -ForegroundColor Red
    if (Test-Path $Backup) { Copy-Item $Backup $Engine -Force; Write-Host "  ✓ Restored backup" -ForegroundColor Yellow }
    Read-Host "  Press Enter to close"
    exit
}

# ── INSTALL PACKAGES ─────────────────────────────────────────
Write-Host ""
Write-Host "  [2/3] Installing Python packages..." -ForegroundColor Cyan
& $pythonCmd -m pip install requests beautifulsoup4 lxml openpyxl --force-reinstall --quiet --user 2>&1 | Out-Null
Write-Host "  ✓ Packages ready" -ForegroundColor Green

# ── REGISTER traceworks COMMAND ──────────────────────────────
Write-Host ""
Write-Host "  [3/3] Checking traceworks command..." -ForegroundColor Cyan

$Launcher = "$TW\traceworks.ps1"
$ProfileDir = Split-Path $PROFILE

if (!(Test-Path $ProfileDir)) { New-Item -ItemType Directory -Path $ProfileDir -Force | Out-Null }

$funcBlock = @"

# ── TraceWorks Skip Tracing System ──────────────────────────
function traceworks {
    powershell -ExecutionPolicy Bypass -File "$Launcher"
}
Set-Alias tw traceworks
# ────────────────────────────────────────────────────────────
"@

$profileContent = ""
if (Test-Path $PROFILE) { $profileContent = Get-Content $PROFILE -Raw -Encoding UTF8 -ErrorAction SilentlyContinue }

if ($profileContent -notmatch "TraceWorks Skip Tracing") {
    try {
        Add-Content -Path $PROFILE -Value $funcBlock -Encoding UTF8 -ErrorAction Stop
        Write-Host "  ✓ traceworks command registered" -ForegroundColor Green
    } catch {
        # OneDrive lock fallback — write .bat and add to PATH
        $bat = "@echo off`r`npowershell -ExecutionPolicy Bypass -File `"$Launcher`" %*"
        [System.IO.File]::WriteAllText("$TW\traceworks.bat", $bat, [System.Text.Encoding]::ASCII)
        $curPath = [Environment]::GetEnvironmentVariable("PATH","User")
        if ($curPath -notlike "*TraceWorks*") {
            [Environment]::SetEnvironmentVariable("PATH","$curPath;$TW","User")
        }
        Write-Host "  ✓ traceworks command registered via PATH fallback" -ForegroundColor Green
    }
} else {
    Write-Host "  ✓ traceworks command already registered" -ForegroundColor Green
}

# ── DONE ─────────────────────────────────────────────────────
Write-Host ""
Write-Host "  ════════════════════════════════════════════════" -ForegroundColor DarkGray
Write-Host "  ✓  ENGINE UPDATED SUCCESSFULLY" -ForegroundColor Green
Write-Host "  ════════════════════════════════════════════════" -ForegroundColor DarkGray
Write-Host ""
Write-Host "  Engine  : $Engine" -ForegroundColor Cyan
Write-Host "  Reports : $Reports" -ForegroundColor Cyan
Write-Host ""
Write-Host "  IMPORTANT: Make sure traceworks.ps1 is also in:" -ForegroundColor Yellow
Write-Host "  $TW" -ForegroundColor Cyan
Write-Host ""

Write-Host "  Launch TraceWorks now? [Y/N]: " -ForegroundColor Yellow -NoNewline
$go = Read-Host " "
if ($go -match '^[Yy]') {
    if (Test-Path $Launcher) {
        & powershell -ExecutionPolicy Bypass -File "$Launcher"
    } else {
        Write-Host "  traceworks.ps1 not found in $TW" -ForegroundColor Red
        Write-Host "  Download it from your Claude session and place it there." -ForegroundColor Yellow
        Read-Host "  Press Enter to close"
    }
} else {
    Read-Host "  Press Enter to close"
}
